114	const relationships = GRAPH_DATA.edges;
115	
116	// Build adjacency
117	const adjacency = {};
118	entities.forEach(e => { adjacency[e.name] = []; });
119	relationships.forEach(r => {
120	  if (adjacency[r.source]) adjacency[r.source].push({ target: r.target, type: r.type, context: r.context });
121	  if (adjacency[r.target]) adjacency[r.target].push({ target: r.source, type: r.type, context: r.context, reverse: true });
122	});
123	
124	// Count connections per node
125	const connectionCount = {};
126	entities.forEach(e => { connectionCount[e.name] = (adjacency[e.name] || []).length; });
127	
128	// Build vis.js data
129	const nodes = new vis.DataSet(entities.map(e => ({
130	  id: e.name,
131	  label: e.name,
132	  title: `${e.type}: ${e.description || ''}`,
133	  color: {
134	    background: TYPE_COLORS[e.type] || TYPE_COLORS.unknown,
