174	  .filter(([t]) => entities.some(e => e.type === t))
175	  .map(([t, c]) => `<div class="legend-item"><div class="legend-dot" style="background:${c}"></div>${t}</div>`)
176	  .join('');
177	document.getElementById('legend').innerHTML = `<h3>Entity Types</h3>${legendHtml}`;
178	
179	// Filters
180	const types = [...new Set(entities.map(e => e.type))].sort();
