196	function applyFilters() {
197	  const query = document.getElementById('search').value.toLowerCase();
198	  const visible = entities.filter(e =>
199	    activeFilters.has(e.type) && (!query || e.name.toLowerCase().includes(query) || (e.description || '').toLowerCase().includes(query))
200	  );
201	  const visibleNames = new Set(visible.map(e => e.name));
202	
203	  nodes.forEach(n => {
204	    nodes.update({ id: n.id, hidden: !visibleNames.has(n.id) });
205	  });
206	  edges.forEach(e => {
207	    edges.update({ id: e.id, hidden: !visibleNames.has(e.from) || !visibleNames.has(e.to) });
208	  });
209	
210	  renderEntityList(visible);
211	}
212	
213	// Entity list
214	function renderEntityList(list) {
215	  const el = document.getElementById('entity-list');
216	  const sorted = [...list].sort((a, b) => (connectionCount[b.name] || 0) - (connectionCount[a.name] || 0));
217	  el.innerHTML = sorted.map(e => `
218	    <div class="entity-item" data-name="${e.name}">
219	      <div class="entity-dot" style="background:${TYPE_COLORS[e.type] || '#888'}"></div>
220	      <span class="entity-name">${e.name}</span>
221	      <span class="entity-count">${connectionCount[e.name] || 0}</span>
222	    </div>
223	  `).join('');
224	
225	  el.querySelectorAll('.entity-item').forEach(item => {
226	    item.onclick = () => focusNode(item.dataset.name);
227	  });
228	}
229	
230	function focusNode(name) {
231	  network.focus(name, { scale: 1.5, animation: { duration: 500, easingFunction: 'easeInOutQuad' } });
232	  network.selectNodes([name]);
233	  showDetail(name);
234	}
235	
236	function showDetail(name) {
237	  const entity = entities.find(e => e.name === name);
238	  if (!entity) return;
239	
240	  document.getElementById('detail-name').textContent = entity.name;
241	  document.getElementById('detail-type').textContent = `${entity.type} · ${entity.date || 'unknown date'}`;
242	  document.getElementById('detail-desc').textContent = entity.description || 'No description';
243	
244	  const conns = adjacency[name] || [];
245	  const connHtml = conns.map(c =>
246	    `<div class="connection-item" onclick="focusNode('${c.target.replace(/'/g, "\\'")}')">
247	      ${c.reverse ? '←' : '→'} <span class="rel-type">${c.type}</span> ${c.target}
248	    </div>`
249	  ).join('');
250	  document.getElementById('detail-connections').innerHTML = connHtml || '<div style="color:#555">No connections</div>';
251	
252	  document.getElementById('detail-panel').classList.add('visible');
253	}
254	
255	document.getElementById('close-detail').onclick = () => {
256	  document.getElementById('detail-panel').classList.remove('visible');
257	};
258	
259	network.on('click', params => {
260	  if (params.nodes.length > 0) showDetail(params.nodes[0]);
261	  else document.getElementById('detail-panel').classList.remove('visible');
262	});
263	
264	network.on('doubleClick', params => {
265	  if (params.nodes.length > 0) {
266	    const name = params.nodes[0];
267	    const neighbors = (adjacency[name] || []).map(c => c.target);
268	    network.fit({ nodes: [name, ...neighbors], animation: { duration: 500 } });
269	  }
270	});
271	
272	document.getElementById('search').addEventListener('input', applyFilters);
273	
274	// Initial render
275	renderEntityList(entities);
276	</script>
277	</body>
