145	<script>
146	const GRAPH_DATA = __GRAPH_DATA__;
147	const CONVERSATIONS = __CONVERSATIONS__;
148	
149	const TYPE_COLORS = {
150	  person: '#6CB4EE', project: '#77DD77', technology: '#FA8072',
151	  concept: '#DDA0DD', file: '#FFFACD', decision: '#F08080',
152	  task: '#87CEEB', problem: '#FFB6C1', database: '#98D8C8', unknown: '#888888'
153	};
154	
155	const entities = GRAPH_DATA.nodes;
156	const relationships = GRAPH_DATA.edges;
157	
158	// Build session-to-entity index
159	const sessionEntities = {};
160	entities.forEach(e => {
161	  (e.sessions || []).forEach(s => {
162	    if (!sessionEntities[s]) sessionEntities[s] = [];
163	    sessionEntities[s].push(e.name);
164	  });
165	});
166	
167	// Build adjacency
168	const adjacency = {};
169	entities.forEach(e => { adjacency[e.name] = []; });
170	relationships.forEach(r => {
171	  if (adjacency[r.source]) adjacency[r.source].push({ target: r.target, type: r.type, context: r.context });
172	  if (adjacency[r.target]) adjacency[r.target].push({ target: r.source, type: r.type, context: r.context, reverse: true });
173	});
174	
175	const connectionCount = {};
176	entities.forEach(e => { connectionCount[e.name] = (adjacency[e.name] || []).length; });
177	
178	// vis.js setup
179	const nodes = new vis.DataSet(entities.map(e => ({
180	  id: e.name, label: e.name,
181	  title: `${e.type}: ${e.description || ''}`,
182	  color: {
183	    background: TYPE_COLORS[e.type] || TYPE_COLORS.unknown,
184	    border: TYPE_COLORS[e.type] || TYPE_COLORS.unknown,
185	    highlight: { background: '#fff', border: TYPE_COLORS[e.type] || TYPE_COLORS.unknown }
186	  },
187	  font: { color: '#e0e0e0', size: Math.max(10, Math.min(18, 10 + connectionCount[e.name])) },
188	  size: Math.max(8, Math.min(30, 8 + connectionCount[e.name] * 2)),
189	  entityType: e.type, description: e.description || '', date: e.date || '',
190	  sessions: e.sessions || []
191	})));
192	
193	const edges = new vis.DataSet(relationships.map((r, i) => ({
194	  id: i, from: r.source, to: r.target, label: r.type,
195	  title: r.context || r.type, arrows: 'to',
196	  color: { color: '#333', highlight: '#e94560', opacity: 0.6 },
197	  font: { color: '#555', size: 9, strokeWidth: 0 },
198	  smooth: { type: 'continuous' }
199	})));
200	
201	const container = document.getElementById('graph');
202	const network = new vis.Network(container, { nodes, edges }, {
203	  physics: {
204	    forceAtlas2Based: { gravitationalConstant: -40, centralGravity: 0.005, springLength: 120, springConstant: 0.02 },
205	    solver: 'forceAtlas2Based', stabilization: { iterations: 150 }
206	  },
207	  interaction: { hover: true, tooltipDelay: 200, keyboard: true },
208	  edges: { width: 0.8, selectionWidth: 2 },
209	  nodes: { shape: 'dot', borderWidth: 2 }
210	});
211	
212	document.getElementById('stats').textContent = `${entities.length} entities · ${relationships.length} relationships`;
213	
214	// Legend
215	const legendHtml = Object.entries(TYPE_COLORS)
216	  .filter(([t]) => entities.some(e => e.type === t))
217	  .map(([t, c]) => `<div class="legend-item"><div class="legend-dot" style="background:${c}"></div>${t}</div>`)
218	  .join('');
219	document.getElementById('legend').innerHTML = `<h3>Entity Types</h3>${legendHtml}`;
220	
221	// Filters
222	const types = [...new Set(entities.map(e => e.type))].sort();
223	let activeFilters = new Set(types);
224	const filtersEl = document.getElementById('filters');
225	types.forEach(t => {
226	  const btn = document.createElement('button');
227	  btn.className = 'filter-btn active';
228	  btn.style.color = TYPE_COLORS[t] || '#888';
229	  btn.textContent = t;
230	  btn.onclick = () => {
231	    if (activeFilters.has(t)) { activeFilters.delete(t); btn.classList.remove('active'); }
232	    else { activeFilters.add(t); btn.classList.add('active'); }
233	    applyFilters();
234	  };
235	  filtersEl.appendChild(btn);
236	});
237	
238	function applyFilters() {
239	  const query = document.getElementById('search').value.toLowerCase();
240	  const visible = entities.filter(e =>
241	    activeFilters.has(e.type) && (!query || e.name.toLowerCase().includes(query) || (e.description || '').toLowerCase().includes(query))
242	  );
243	  const visibleNames = new Set(visible.map(e => e.name));
244	  nodes.forEach(n => { nodes.update({ id: n.id, hidden: !visibleNames.has(n.id) }); });
245	  edges.forEach(e => { edges.update({ id: e.id, hidden: !visibleNames.has(e.from) || !visibleNames.has(e.to) }); });
246	  renderEntityList(visible);
247	}
248	
249	function renderEntityList(list) {
250	  const el = document.getElementById('entity-list');
251	  const sorted = [...list].sort((a, b) => (connectionCount[b.name] || 0) - (connectionCount[a.name] || 0));
252	  el.innerHTML = sorted.map(e => `
